import { type JSX, useEffect, useMemo, useState } from 'react';

import type { Element } from '@bim-ai/core';
import { PROJECT_TEMPLATES } from '../../onboarding/projectTemplates';
import { GeoMapPicker, type GeoAnchor } from './GeoMapPicker';

function defaultBbox(lat: number, lon: number, radiusM = 300) {
  const dLat = radiusM / 111_319.5;
  const dLon = radiusM / (111_319.5 * Math.cos((lat * Math.PI) / 180));
  return {
    bboxNorth: lat + dLat,
    bboxSouth: lat - dLat,
    bboxEast: lon + dLon,
    bboxWest: lon - dLon,
  };
}

type CommandDispatcher = (cmd: Record<string, unknown>) => void | Promise<void>;

type SetupStatus = 'ready' | 'missing' | 'partial';
type SetupSectionKey =
  | 'project-info'
  | 'units'
  | 'levels'
  | 'grids'
  | 'positioning'
  | 'sun'
  | 'phases'
  | 'links'
  | 'templates'
  | 'standards';

const LENGTH_UNITS = [
  ['millimeter', 'Millimeters'],
  ['centimeter', 'Centimeters'],
  ['meter', 'Meters'],
  ['inch', 'Inches'],
  ['foot', 'Feet'],
] as const;

const LOCALES = [
  ['en-US', 'English (US)'],
  ['en-GB', 'English (UK)'],
  ['de-DE', 'Deutsch (DE)'],
] as const;

const DAYLIGHT_SAVING_OPTIONS = [
  ['auto', 'Auto'],
  ['on', 'On'],
  ['off', 'Off'],
] as const;

function slugToken(input: string): string {
  return (
    input
      .trim()
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, '-')
      .replace(/^-+|-+$/g, '')
      .slice(0, 32) || 'level'
  );
}

function statusFor(ok: boolean, partial = false): SetupStatus {
  if (ok) return 'ready';
  return partial ? 'partial' : 'missing';
}

function statusLabel(status: SetupStatus): string {
  if (status === 'ready') return 'Ready';
  if (status === 'partial') return 'Partial';
  return 'Missing';
}

function StatusPill({ status }: { status: SetupStatus }): JSX.Element {
  const cls =
    status === 'ready'
      ? 'border-emerald-700/40 bg-emerald-950/20 text-emerald-700'
      : status === 'partial'
        ? 'border-amber-700/40 bg-amber-950/20 text-amber-700'

