1	import { render, screen, fireEvent, waitFor, cleanup } from '@testing-library/react';
2	import { afterEach, describe, it, expect, vi } from 'vitest';
3	import { PhaseManagerDialog } from './PhaseManagerDialog';
4	import type { Element } from '@bim-ai/core';
5	
6	afterEach(() => {
7	  cleanup();
8	});
9	
10	function makePhase(id: string, name: string, ord: number, description = ''): Element {
11	  return { kind: 'phase', id, name, ord, description } as Element;
12	}
13	
14	function makeWall(id: string, phaseId: string): Element {
15	  return { kind: 'wall', id, phaseId } as unknown as Element;
16	}
17	
18	const baseElements: Record<string, Element> = {
19	  'phase-existing': makePhase('phase-existing', 'Existing', 0, 'Bestand'),
20	  'phase-demo': makePhase('phase-demo', 'Demolition', 1),
21	  'phase-new': makePhase('phase-new', 'New Construction', 2),
22	};
23	
24	describe('PhaseManagerDialog', () => {
25	  it('renders phases in sequence order', () => {
26	    render(
27	      <PhaseManagerDialog
28	        open
29	        onClose={vi.fn()}
30	        elementsById={baseElements}
31	        onSemanticCommand={vi.fn()}
32	      />,
33	    );
34	    const rows = screen.getAllByTestId(/^phase-row-/);
35	    expect(rows).toHaveLength(3);
36	    expect(rows[0].textContent).toContain('Existing');
37	    expect(rows[1].textContent).toContain('Demolition');
38	    expect(rows[2].textContent).toContain('New Construction');
39	  });
40	
41	  it('shows element count per phase', () => {
42	    const elements: Record<string, Element> = {
43	      ...baseElements,
44	      wall1: makeWall('wall1', 'phase-existing'),
45	      wall2: makeWall('wall2', 'phase-existing'),
46	      wall3: makeWall('wall3', 'phase-new'),
47	    };
48	    render(
49	      <PhaseManagerDialog
50	        open
51	        onClose={vi.fn()}
52	        elementsById={elements}
53	        onSemanticCommand={vi.fn()}
54	      />,
55	    );
56	    const existingRow = screen.getByTestId('phase-row-phase-existing');
57	    expect(existingRow).toHaveTextContent('2');
58	    const newRow = screen.getByTestId('phase-row-phase-new');
59	    expect(newRow).toHaveTextContent('1');
60	  });
61	
62	  it('dispatches createPhase when add is clicked', async () => {
63	    const dispatch = vi.fn();
64	    render(
65	      <PhaseManagerDialog
66	        open
67	        onClose={vi.fn()}
68	        elementsById={baseElements}
69	        onSemanticCommand={dispatch}
70	      />,
71	    );
72	    fireEvent.change(screen.getByTestId('phase-new-name'), { target: { value: 'Renovation' } });
73	    fireEvent.click(screen.getByTestId('phase-add-btn'));
74	    await waitFor(() => expect(dispatch).toHaveBeenCalledTimes(1));
75	    const cmd = dispatch.mock.calls[0][0] as Record<string, unknown>;
76	    expect(cmd.type).toBe('createPhase');
77	    expect(cmd.name).toBe('Renovation');
78	    expect(typeof cmd.id).toBe('string');
79	    expect(cmd.ord).toBe(3);
80	  });
81	
82	  it('dispatches updateElementProperty on rename', async () => {
83	    const dispatch = vi.fn();
84	    render(
85	      <PhaseManagerDialog
86	        open
87	        onClose={vi.fn()}
88	        elementsById={baseElements}
89	        onSemanticCommand={dispatch}
90	      />,
91	    );
92	    fireEvent.click(screen.getByText('Existing'));
93	    const input = screen.getByTestId('phase-edit-name');
94	    fireEvent.change(input, { target: { value: 'Bestand (renamed)' } });
95	    fireEvent.click(screen.getByTestId('phase-save-btn'));
96	    await waitFor(() => expect(dispatch).toHaveBeenCalled());
97	    const cmd = dispatch.mock.calls[0][0] as Record<string, unknown>;
98	    expect(cmd.type).toBe('updateElementProperty');
99	    expect(cmd.elementId).toBe('phase-existing');
100	    expect(cmd.key).toBe('name');
101	    expect(cmd.value).toBe('Bestand (renamed)');
102	  });
103	
104	  it('shows delete confirmation with element count warning', () => {
105	    const elements: Record<string, Element> = {
106	      ...baseElements,
107	      wall1: makeWall('wall1', 'phase-existing'),
108	    };
109	    render(
110	      <PhaseManagerDialog
111	        open
112	        onClose={vi.fn()}
113	        elementsById={elements}
114	        onSemanticCommand={vi.fn()}
115	      />,
116	    );
117	    fireEvent.click(screen.getByTestId('phase-delete-phase-existing'));
118	    expect(screen.getByRole('alertdialog')).toBeInTheDocument();
119	    expect(screen.getByText(/1 element.*assigned/)).toBeInTheDocument();
120	  });
121	
122	  it('dispatches deleteElement after confirmation', async () => {
123	    const dispatch = vi.fn();
124	    render(
125	      <PhaseManagerDialog
126	        open
127	        onClose={vi.fn()}
128	        elementsById={baseElements}
129	        onSemanticCommand={dispatch}
130	      />,
131	    );
132	    fireEvent.click(screen.getByTestId('phase-delete-phase-demo'));
133	    fireEvent.click(screen.getByTestId('phase-confirm-delete'));
134	    await waitFor(() => expect(dispatch).toHaveBeenCalledTimes(1));
135	    const cmd = dispatch.mock.calls[0][0] as Record<string, unknown>;
136	    expect(cmd.type).toBe('deleteElement');
137	    expect(cmd.elementId).toBe('phase-demo');
138	  });
139	
140	  it('closes on Escape key', () => {
141	    const onClose = vi.fn();
142	    render(
143	      <PhaseManagerDialog
144	        open
145	        onClose={onClose}
146	        elementsById={baseElements}
147	        onSemanticCommand={vi.fn()}
148	      />,
149	    );
150	    fireEvent.keyDown(window, { key: 'Escape' });
151	    expect(onClose).toHaveBeenCalledTimes(1);
152	  });
153	
154	  it('returns null when closed', () => {
155	    const { container } = render(
156	      <PhaseManagerDialog
157	        open={false}
158	        onClose={vi.fn()}
159	        elementsById={baseElements}
160	        onSemanticCommand={vi.fn()}
161	      />,
162	    );
163	    expect(container.firstChild).toBeNull();
164	  });
165	});

