1	import type { ReactElement } from 'react';
2	
3	import type { Element, Sheet, TitleblockType } from '@bim-ai/core';
4	
5	// Cartouche dimensions (bottom-right, per A1 convention)
6	const CARTOUCHE_W_MM = 148;
7	const CARTOUCHE_H_MM = 50;
8	
9	const SHEET_SIZE_MM: Record<string, { w: number; h: number }> = {
10	  A0: { w: 1189, h: 841 },
11	  A1: { w: 841, h: 594 },
12	  A2: { w: 594, h: 420 },
13	  A3: { w: 420, h: 297 },
14	};
15	
16	export type SheetCanvasProps = {
17	  elementsById: Record<string, Element>;
18	  preferredSheetId?: string;
19	  modelId?: string;
20	  evidenceFullBleed?: boolean;
21	};
22	
23	function resolveTokenValue(slotName: string, sheet: Sheet): string {
24	  const meta = sheet.metadata ?? {};
25	  switch (slotName) {
26	    case 'projectName':
27	      return meta.projectName ?? '';
28	    case 'drawnBy':
29	      return meta.drawnBy ?? '';
30	    case 'checkedBy':
31	      return meta.checkedBy ?? '';
32	    case 'date':
33	      return meta.date ?? '';
34	    case 'revision':
35	      return meta.revision ?? '';
36	    case 'number':
37	      return sheet.number ?? '';
38	    default:
39	      return '';
40	  }
41	}
42	
43	function findSheet(
44	  elementsById: Record<string, Element>,
45	  preferredSheetId?: string,
46	): Sheet | undefined {
47	  if (preferredSheetId) {
48	    const el = elementsById[preferredSheetId];
49	    if (el?.kind === 'sheet') return el as Sheet;
50	  }
51	  return (Object.values(elementsById) as Element[]).find((e): e is Sheet => e.kind === 'sheet');
52	}
53	
54	function findTitleblockType(
55	  elementsById: Record<string, Element>,
56	  sheet: Sheet,
57	): TitleblockType | undefined {
58	  if (sheet.titleblockTypeId) {
59	    const el = elementsById[sheet.titleblockTypeId];
60	    if (el?.kind === 'titleblock_type') return el as TitleblockType;
61	  }
62	  return (Object.values(elementsById) as Element[]).find(
63	    (e): e is TitleblockType => e.kind === 'titleblock_type',
64	  );
65	}
66	
67	export function SheetCanvas({ elementsById, preferredSheetId }: SheetCanvasProps): ReactElement {
68	  const sheet = findSheet(elementsById, preferredSheetId);
69	  const titleblockType = sheet ? findTitleblockType(elementsById, sheet) : undefined;
70	
71	  // Fallback dimensions when no sheet found
72	  const landscape = (sheet?.orientation ?? 'landscape') === 'landscape';
73	  const sizeKey = sheet?.size ?? 'A1';
74	  const base = SHEET_SIZE_MM[sizeKey] ?? SHEET_SIZE_MM['A1'];
75	  const sheetW = landscape ? base.w : base.h;
76	  const sheetH = landscape ? base.h : base.w;
77	
78	  // Scale to fit viewport (max 1200px wide)
79	  const maxPx = 1200;
80	  const scale = maxPx / sheetW;
81	  const svgW = sheetW * scale;
82	  const svgH = sheetH * scale;
83	
84	  const toSvgX = (mm: number) => mm * scale;
85	  const toSvgY = (mm: number) => mm * scale;
86	
87	  const cartoucheX = sheetW - CARTOUCHE_W_MM;
88	  const cartoucheY = sheetH - CARTOUCHE_H_MM;
89	
90	  const placements = sheet?.viewPlacements ?? [];
91	
92	  // Drawable area (excluding cartouche column)
93	  const drawableW = sheetW - CARTOUCHE_W_MM - 20;
94	  const drawableH = sheetH - 20;
95	  const drawableCenterX = toSvgX(10 + drawableW / 2);
96	  const drawableCenterY = toSvgY(10 + drawableH / 2);
97	
98	  if (!sheet) {
99	    // No sheet element at all — render minimal placeholder
100	    /* eslint-disable bim-ai/no-hex-in-chrome -- placeholder SVG uses neutral greys without tokens */
101	    const phStroke = '#ccc';
102	    const phTextPrimary = '#aaa';
103	    const phTextSecondary = '#bbb';
104	    /* eslint-enable bim-ai/no-hex-in-chrome */
105	    return (
106	      <svg
107	        width={svgW}
108	        height={svgH}
109	        viewBox={`0 0 ${svgW} ${svgH}`}
110	        style={{ display: 'block', background: 'white' }}
111	      >
112	        <rect
113	          x={0}
114	          y={0}
115	          width={svgW}
116	          height={svgH}
117	          fill="white"
118	          stroke={phStroke}
119	          strokeWidth={1}
120	        />
121	        <text
122	          x={svgW / 2}
123	          y={svgH / 2 - 8}
124	          textAnchor="middle"
125	          dominantBaseline="middle"
126	          style={{ fontSize: 11, fill: phTextPrimary }}
127	        >
128	          No sheet found
129	        </text>
130	        <text
131	          x={svgW / 2}
132	          y={svgH / 2 + 8}
