import { cleanup, fireEvent, render, screen, waitFor } from '@testing-library/react';
import { afterEach, describe, expect, it, vi } from 'vitest';

import type { Element } from '@bim-ai/core';

import { ProjectInfoDialog } from './ProjectInfoDialog';

afterEach(() => {
  cleanup();
});

function makeProjectSettings(overrides: Record<string, unknown> = {}): Element {
  return {
    kind: 'project_settings',
    id: 'project_settings',
    name: 'My Project',
    projectNumber: 'PRJ-001',
    clientName: 'ACME Corp',
    projectStatus: 'Active',
    authorName: 'Jane Doe',
    issueDate: '2026-01-15',
    checkDate: 'John Smith',
    projectDescription: 'A test project',
    projectAddress: '123 Main St',
    ...overrides,
  } as unknown as Element;
}

const baseElements: Record<string, Element> = {
  project_settings: makeProjectSettings(),
};

describe('ProjectInfoDialog', () => {
  it('returns null when closed', () => {
    const { container } = render(
      <ProjectInfoDialog
        open={false}
        onClose={vi.fn()}
        elementsById={baseElements}
        onSemanticCommand={vi.fn()}
      />,
    );
    expect(container.firstChild).toBeNull();
  });

  it('populates fields from project_settings on open', () => {
    render(
      <ProjectInfoDialog
        open
        onClose={vi.fn()}
        elementsById={baseElements}
        onSemanticCommand={vi.fn()}
      />,
    );
    expect(screen.getByTestId('project-info-name')).toHaveValue('My Project');
    expect(screen.getByTestId('project-info-number')).toHaveValue('PRJ-001');
    expect(screen.getByTestId('project-info-client')).toHaveValue('ACME Corp');
    expect(screen.getByTestId('project-info-author')).toHaveValue('Jane Doe');
    expect(screen.getByTestId('project-info-issuedate')).toHaveValue('2026-01-15');
  });

  it('dispatches updateElementProperty commands for each field on save', async () => {
    const dispatch = vi.fn();
    render(
      <ProjectInfoDialog
        open
        onClose={vi.fn()}
        elementsById={baseElements}
        onSemanticCommand={dispatch}
      />,
    );
    fireEvent.change(screen.getByTestId('project-info-name'), {
      target: { value: 'New Name' },
    });
    fireEvent.click(screen.getByTestId('project-info-save'));
    await waitFor(() => expect(dispatch).toHaveBeenCalled());
