import { type JSX, useEffect, useRef, useState } from 'react';

import type { Element } from '@bim-ai/core';

type CommandDispatcher = (cmd: Record<string, unknown>) => void | Promise<void>;

type ProjectSettings = Extract<Element, { kind: 'project_settings' }>;

function getProjectSettings(elementsById: Record<string, Element>): ProjectSettings | undefined {
  const direct = elementsById['project_settings'];
  if (direct?.kind === 'project_settings') return direct as ProjectSettings;
  return (Object.values(elementsById) as Element[]).find(
    (e): e is ProjectSettings => e.kind === 'project_settings',
  );
}

interface Draft {
  name: string;
  projectNumber: string;
  projectAddress: string;
  projectStatus: string;
  clientName: string;
  authorName: string;
  issueDate: string;
  checkDate: string;
  projectDescription: string;
  projectNorthAngleDeg: string;
}

function emptyDraft(): Draft {
  return {
    name: '',
    projectNumber: '',
    projectAddress: '',
    projectStatus: '',
    clientName: '',
    authorName: '',
    issueDate: '',
    checkDate: '',
    projectDescription: '',
    projectNorthAngleDeg: '0',
  };
}

function draftFromSettings(ps: ProjectSettings | undefined): Draft {
  if (!ps) return emptyDraft();
  return {
    name: ps.name ?? '',
    projectNumber: ps.projectNumber ?? '',
    projectAddress: ps.projectAddress ?? '',
    projectStatus: ps.projectStatus ?? '',
    clientName: ps.clientName ?? '',
    authorName: ps.authorName ?? '',
    issueDate: ps.issueDate ?? '',
    checkDate: ps.checkDate ?? '',
    projectDescription: ps.projectDescription ?? '',
    projectNorthAngleDeg: String(ps.projectNorthAngleDeg ?? 0),
  };
}

export function ProjectInfoDialog({
  open,
  onClose,
  elementsById,
  onSemanticCommand,
}: {
  open: boolean;
  onClose: () => void;
  elementsById: Record<string, Element>;
  onSemanticCommand: CommandDispatcher;
}): JSX.Element | null {
  const dialogRef = useRef<HTMLDivElement | null>(null);
  const [draft, setDraft] = useState<Draft>(emptyDraft);
  const [busy, setBusy] = useState(false);
  const [message, setMessage] = useState<string | null>(null);

  const ps = getProjectSettings(elementsById);

  useEffect(() => {
    if (open) {
      setDraft(draftFromSettings(ps));
      setMessage(null);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [open]);

  useEffect(() => {
    if (open) dialogRef.current?.focus();
  }, [open]);

  useEffect(() => {
    if (!open) return;
    const handler = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [open, onClose]);

  const save = async () => {
    const sid = ps?.id ?? 'project_settings';
    const cmds: Record<string, unknown>[] = [];
    if (!ps) {
      cmds.push({ type: 'upsertProjectSettings', id: sid });
    }
    const fields: Array<[keyof Draft, string]> = [
      ['name', draft.name],
      ['projectNumber', draft.projectNumber],
      ['projectAddress', draft.projectAddress],
      ['projectStatus', draft.projectStatus],
      ['clientName', draft.clientName],
      ['authorName', draft.authorName],
      ['issueDate', draft.issueDate],
      ['checkDate', draft.checkDate],
      ['projectDescription', draft.projectDescription],
    ];
    for (const [key, value] of fields) {
      cmds.push({ type: 'updateElementProperty', elementId: sid, key, value });
    }
    const northAngle = parseFloat(draft.projectNorthAngleDeg);
    if (Number.isFinite(northAngle)) {
      cmds.push({
        type: 'updateElementProperty',
        elementId: sid,
        key: 'projectNorthAngleDeg',
        value: String(northAngle),
      });
    }
    setBusy(true);
    setMessage(null);
    try {
      for (const cmd of cmds) await onSemanticCommand(cmd);
      setMessage('Project information saved.');
    } catch {
      setMessage('Save failed — check your connection.');
    } finally {
      setBusy(false);
    }
  };

  if (!open) return null;

  return (
    <div
      role="dialog"
      aria-modal="true"
      aria-label="Project Information"
      style={{
        position: 'fixed',
        inset: 0,
        zIndex: 200,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: 'rgba(0,0,0,0.4)',
      }}
      onMouseDown={(e) => {
        if (e.target === e.currentTarget) onClose();
      }}
    >
      <div
        ref={dialogRef}
        tabIndex={-1}
        style={{
          background: 'var(--color-surface)',
          border: '1px solid var(--color-border)',
          borderRadius: 6,
          boxShadow: '0 4px 24px rgba(0,0,0,0.2)',
          width: 560,
          maxHeight: '85vh',
          display: 'flex',
          flexDirection: 'column',
          overflow: 'hidden',
          outline: 'none',
        }}
        onMouseDown={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div
          style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            padding: '12px 16px',
            borderBottom: '1px solid var(--color-border)',
            flexShrink: 0,
          }}
        >
          <span style={{ fontWeight: 600, fontSize: 14 }}>Project Information</span>
          <button
            onClick={onClose}
            aria-label="Close"
            style={{
              background: 'none',
              border: 'none',
              cursor: 'pointer',
              fontSize: 16,
              color: 'var(--color-text-secondary)',
              padding: '2px 6px',
            }}
          >
            ×
          </button>
        </div>

        {/* Body */}
        <div style={{ overflowY: 'auto', flex: 1, padding: '16px' }}>
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: '1fr 1fr',
              gap: '12px',
            }}
          >
            <Field
              label="Project name"
              testId="project-info-name"
              value={draft.name}
              onChange={(v) => setDraft((d) => ({ ...d, name: v }))}
            />
            <Field
              label="Project number"
              testId="project-info-number"
              value={draft.projectNumber}
              onChange={(v) => setDraft((d) => ({ ...d, projectNumber: v }))}
            />
            <Field
              label="Client"
              testId="project-info-client"
              value={draft.clientName}
              onChange={(v) => setDraft((d) => ({ ...d, clientName: v }))}
            />
            <Field
              label="Status"
              testId="project-info-status"
              value={draft.projectStatus}
              onChange={(v) => setDraft((d) => ({ ...d, projectStatus: v }))}
            />
            <Field
              label="Author"
              testId="project-info-author"
              value={draft.authorName}
              onChange={(v) => setDraft((d) => ({ ...d, authorName: v }))}
            />
            <Field
              label="Checked by"
              testId="project-info-checkdate"
              value={draft.checkDate}
              onChange={(v) => setDraft((d) => ({ ...d, checkDate: v }))}
            />
            <Field
              label="Issue date"
              testId="project-info-issuedate"
              value={draft.issueDate}
              onChange={(v) => setDraft((d) => ({ ...d, issueDate: v }))}
            />
            <Field
              label="True North angle (°)"
              testId="project-info-north-angle"
              value={draft.projectNorthAngleDeg}
              onChange={(v) => setDraft((d) => ({ ...d, projectNorthAngleDeg: v }))}
            />
          </div>
          <div style={{ marginTop: 12 }}>
            <label
              style={{
                display: 'block',
                fontSize: 11,
                color: 'var(--color-text-secondary)',
                marginBottom: 4,
              }}
            >
              Address
            </label>
            <textarea
              data-testid="project-info-address"
              value={draft.projectAddress}
              onChange={(e) => setDraft((d) => ({ ...d, projectAddress: e.currentTarget.value }))}
              rows={3}
              style={{
                width: '100%',
                fontSize: 13,
                border: '1px solid var(--color-border)',
                borderRadius: 4,
                padding: '6px 8px',
                background: 'var(--color-surface)',
                color: 'var(--color-text)',
                resize: 'vertical',
                boxSizing: 'border-box',
              }}
            />
          </div>
          <div style={{ marginTop: 12 }}>
            <label
              style={{
                display: 'block',
                fontSize: 11,
                color: 'var(--color-text-secondary)',
                marginBottom: 4,
              }}
            >
              Description
            </label>
            <textarea
              data-testid="project-info-description"
              value={draft.projectDescription}
              onChange={(e) =>
                setDraft((d) => ({ ...d, projectDescription: e.currentTarget.value }))
              }
              rows={3}
              style={{
                width: '100%',
                fontSize: 13,
                border: '1px solid var(--color-border)',
                borderRadius: 4,
                padding: '6px 8px',
                background: 'var(--color-surface)',
                color: 'var(--color-text)',
                resize: 'vertical',
                boxSizing: 'border-box',
              }}
            />
          </div>
        </div>

        {/* Footer */}
        <div
          style={{
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
            padding: '10px 16px',
            borderTop: '1px solid var(--color-border)',
            flexShrink: 0,
          }}
        >
          <span
            style={{
              fontSize: 12,
              color: message?.startsWith('Save failed')
                ? 'var(--color-error, #e55)'
                : 'var(--color-text-secondary)',
            }}
          >
            {message ?? ''}
          </span>
          <div style={{ display: 'flex', gap: 8 }}>
            <button
              onClick={onClose}
              style={{
                fontSize: 13,
                padding: '5px 14px',
                borderRadius: 4,
                border: '1px solid var(--color-border)',
                background: 'var(--color-surface)',
                color: 'var(--color-text)',
                cursor: 'pointer',
              }}
            >
              Cancel
            </button>
            <button
              data-testid="project-info-save"
              disabled={busy}
              onClick={() => void save()}
              style={{
                fontSize: 13,
                padding: '5px 14px',
                borderRadius: 4,
                border: 'none',
                background: 'var(--color-accent, #2563eb)',
                color: '#fff',
                cursor: 'pointer',
                opacity: busy ? 0.6 : 1,
              }}
            >
              {busy ? 'Saving…' : 'Save'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

function Field({
  label,
  value,
  onChange,
  testId,
}: {
  label: string;
  value: string;
  onChange: (v: string) => void;
  testId?: string;
}): JSX.Element {
  return (
    <label style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
      <span style={{ fontSize: 11, color: 'var(--color-text-secondary)' }}>{label}</span>
      <input
        data-testid={testId}
        type="text"
        value={value}
        onChange={(e) => onChange(e.currentTarget.value)}
        style={{
          fontSize: 13,
          border: '1px solid var(--color-border)',
          borderRadius: 4,
          padding: '5px 8px',
          background: 'var(--color-surface)',
          color: 'var(--color-text)',
        }}
      />
    </label>
  );
}

import { useState, type JSX } from 'react';

import type { Element, PhaseFilter } from '@bim-ai/core';

import { PhaseDropdown } from './PhaseDropdown';
import type { PlanDetailLevel } from './planDetailLevelLines';
import { PlanDetailLevelToolbar } from './PlanDetailLevelToolbar';
import { ColorSchemeDialog } from './ColorSchemeDialog';
import type { ColorSchemeRoomEntry } from './ColorSchemeDialog';
import { resolveViewRange } from './planProjection';
import { ViewRangeDialog } from './ViewRangeDialog';
import type { ViewRangeValues } from './ViewRangeDialog';

export type PlanViewHeaderProps = {
  phaseFilter: PhaseFilter;
  onPhaseFilterChange: (value: PhaseFilter) => void;
  detailLevel: PlanDetailLevel;
  onDetailLevelChange: (value: PlanDetailLevel) => void;
  /** Active plan view ID — used to read current view range values. */
  activePlanViewId?: string | null;
  /** All elements, for reading plan_view fields. */
  elementsById?: Record<string, Element>;
  /** Callback to persist view range changes for the active plan view. */
  onViewRangeApply?: (planViewId: string, values: ViewRangeValues) => void;
  /** D7 - ceiling/reflected ceiling plan badge. */
  viewSubtype?: string;
  /** When true, shows the Color Scheme button (only for plan views with rooms). */
  hasRooms?: boolean;
  /** Current color scheme applied to this view (if any). */
  currentColorScheme?: { category: string; colorMap: Record<string, string> };
  /** Rooms available for building the color scheme table. */
  rooms?: ColorSchemeRoomEntry[];
  /** Called when the user applies a color scheme in the dialog. */
  onColorSchemeApply?: (payload: {
    viewId: string;
    schemeCategory: string;
    colorMap: Record<string, string>;
  }) => void;
  /** F6: angle from project north to true north. When provided, shows the True North toggle. */
  projectNorthAngleDeg?: number;
  /** F6: whether the canvas is currently rotated to true north. */
  trueNorthActive?: boolean;
  /** F6: called when the user toggles the True North mode. */
  onTrueNorthToggle?: (active: boolean) => void;
};

export function PlanViewHeader({
  phaseFilter,
  onPhaseFilterChange,
  detailLevel,
  onDetailLevelChange,
  activePlanViewId,
  elementsById,
  onViewRangeApply,
  viewSubtype,
  hasRooms = false,
  currentColorScheme,
  rooms = [],
  onColorSchemeApply,
  projectNorthAngleDeg,
  trueNorthActive = false,
  onTrueNorthToggle,
}: PlanViewHeaderProps): JSX.Element {
  const [viewRangeOpen, setViewRangeOpen] = useState(false);
  const [colorSchemeOpen, setColorSchemeOpen] = useState(false);

  const viewRange = resolveViewRange(elementsById ?? {}, activePlanViewId ?? undefined);

  return (
    <div className="plan-view-header flex items-center gap-2 px-2 py-1">
      <PlanDetailLevelToolbar value={detailLevel} onChange={onDetailLevelChange} />
      <PhaseDropdown value={phaseFilter} onChange={onPhaseFilterChange} />
      {viewSubtype === 'ceiling_plan' ? (
        <span
          data-testid="plan-view-header-rcp-badge"
          style={{
            padding: '1px 6px',
            fontSize: 10,
            fontWeight: 600,
            border: '1px solid var(--color-border)',
            borderRadius: 3,
            color: 'var(--color-muted)',
            whiteSpace: 'nowrap',
          }}
        >
          RCP
        </span>
      ) : null}
      {hasRooms && onColorSchemeApply ? (
        <button
          type="button"
          data-testid="color-scheme-dialog-trigger"
          onClick={() => setColorSchemeOpen(true)}
          style={{
            padding: '2px 8px',
            fontSize: 11,
            border: '1px solid var(--color-border)',
            borderRadius: 4,
            cursor: 'pointer',
            background: 'transparent',
            color: 'var(--color-foreground)',
            whiteSpace: 'nowrap',
          }}
        >
          Color Scheme…
        </button>
      ) : null}
      {activePlanViewId && onViewRangeApply ? (
        <button
          type="button"
          data-testid="view-range-btn"
          onClick={() => setViewRangeOpen(true)}
          style={{
            padding: '2px 8px',
            fontSize: 11,
            border: '1px solid var(--color-border)',
            borderRadius: 4,
            cursor: 'pointer',
            background: 'transparent',
            color: 'var(--color-foreground)',
            whiteSpace: 'nowrap',
          }}
        >
          View Range…
        </button>
      ) : null}
      {viewRangeOpen && activePlanViewId && onViewRangeApply ? (
        <ViewRangeDialog
          open={viewRangeOpen}
          viewId={activePlanViewId}
          viewRangeTopMm={viewRange.viewRangeTopMm}
          cutPlaneOffsetMm={viewRange.cutPlaneOffsetMm}
          viewRangeBottomMm={viewRange.viewRangeBottomMm}
          viewDepth={viewRange.viewDepth}
          onClose={() => setViewRangeOpen(false)}
          onApply={(values) => {
            onViewRangeApply(activePlanViewId, values);
          }}
        />
      ) : null}
      {colorSchemeOpen && activePlanViewId && onColorSchemeApply ? (
        <ColorSchemeDialog
          open={colorSchemeOpen}
          viewId={activePlanViewId}
          rooms={rooms}
          currentScheme={currentColorScheme}
          onClose={() => setColorSchemeOpen(false)}
          onApply={(payload) => {
            onColorSchemeApply(payload);
            setColorSchemeOpen(false);
          }}
        />
      ) : null}
      {projectNorthAngleDeg !== undefined && onTrueNorthToggle ? (
        <button
          type="button"
          data-testid="true-north-toggle"
          aria-pressed={trueNorthActive}
          onClick={() => onTrueNorthToggle(!trueNorthActive)}
          title={
            trueNorthActive
              ? `True North active (${projectNorthAngleDeg}°) — click to disable`
              : `True North off — click to rotate ${projectNorthAngleDeg}°`
          }
          style={{
            padding: '2px 8px',
            fontSize: 11,
            border: '1px solid var(--color-border)',
            borderRadius: 4,
            cursor: 'pointer',
            background: trueNorthActive ? 'var(--color-accent, #2563eb)' : 'transparent',
            color: trueNorthActive ? '#fff' : 'var(--color-foreground)',
            whiteSpace: 'nowrap',
          }}
        >
          N ↑ {projectNorthAngleDeg}°
        </button>
      ) : null}
    </div>
  );
}

import { create } from 'zustand';

import type { SunOverlayValues } from './viewport/SunOverlay';

type SunStore = {
  values: SunOverlayValues;
  azimuthDeg: number;
  elevationDeg: number;
  /** F6: project north offset added to the geographic azimuth for plan-view display. */
  projectNorthOffsetDeg: number;
  setValues: (patch: Partial<SunOverlayValues>) => void;
  setComputedPosition: (azimuth: number, elevation: number) => void;
  setProjectNorthOffsetDeg: (deg: number) => void;
  /** Azimuth adjusted for project north rotation — use this for plan-view sun direction. */
  displayAzimuthDeg: () => number;
};

const DEFAULT_VALUES: SunOverlayValues = {
  latitudeDeg: 48.14,
  longitudeDeg: 11.58,
  dateIso: new Date().toISOString().slice(0, 10),
  hours: 14,
  minutes: 0,
  daylightSavingStrategy: 'auto',
};

export const useSunStore = create<SunStore>((set, get) => ({
  values: DEFAULT_VALUES,
  azimuthDeg: 145,
  elevationDeg: 35,
  projectNorthOffsetDeg: 0,
  setValues: (patch) => set((s) => ({ values: { ...s.values, ...patch } })),
  setComputedPosition: (azimuthDeg, elevationDeg) => set({ azimuthDeg, elevationDeg }),
  setProjectNorthOffsetDeg: (deg) => set({ projectNorthOffsetDeg: deg }),
  displayAzimuthDeg: () => {
    const s = get();
    return (((s.azimuthDeg - s.projectNorthOffsetDeg) % 360) + 360) % 360;
  },
}));

