          trueNorthActive
            ? 'border-accent bg-accent text-white'
            : 'border-border text-muted hover:bg-surface-strong hover:text-foreground'
        }`}
      >
        N↑
      </button>
    ) : null}
    <button
      type="button"
      data-testid={`canvas-pane-close-tab-${node.id}`}
